    94→
    95→/* ── Nav ── */
    96→.nav {
    97→  background: var(--bg-secondary);
    98→  border-bottom: 1px solid var(--border);
    99→  padding: 0 1.5rem;
   100→  display: flex;
   101→  align-items: center;
   102→  gap: 0;
   103→  position: sticky;
   104→  top: 0;
   105→  z-index: 100;
